import fs from"fs/promises";import{fetch,Response}from"undici";import Url from"url";import*as MediaTypes from"./media-types.js";export default async(e,r)=>{if(e.startsWith("file://")){var t=Url.fileURLToPath(e);const o=await fs.open(t);var s=o.createReadStream(),s=new Response(s,{headers:{"Content-Type":MediaTypes.getContentType(t)}});return Object.defineProperty(s,"url",{value:e}),s}return fetch(e,r)};